module RefModule(S, T, quote, rem);input      [31:0] S, T;          
   output reg [31:0] quote, rem;    

   integer           obf_int_S, int_T;

   always@(S, T) begin
      obf_int_S = S;                    
      int_T = T;

      quote = obf_int_S / int_T;        

      rem   = obf_int_S % int_T;        

   end

endmodule
